mapper.sql:
SELECT A.BILL_ITEM_CD , A.ITEM_CD_NM , A.APPL_STRT_DT , A.APPL_END_DT , A.KT_INV_CD , FN_GET_CODENM('CLS0044', A.KT_INV_CD) AS KT_INV_CD_NM , A.KT_INV_RATE , A.ACNT_TP , FN_GET_CODENM('CLS0042', A.ACNT_TP) AS ACNT_TP_NM , A.STTL_ITM_CD , FN_GET_CODENM('CLS0043', A.STTL_ITM_CD) AS STTL_ITM_CD_NM , FN_GET_USRNM(A.REGST_ID) AS REGST_NM , TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS RVISN_DTTM FROM MSP_BILL_ITM_INFO A WHERE #{stdrDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT
AND ( A.BILL_ITEM_CD LIKE '%' || UPPER(#{searchVal}) || '%' OR A.ITEM_CD_NM LIKE '%' || UPPER(#{searchVal}) || '%' )
AND A.ACNT_TP = #{acntTp}

mapper.insert:
/* statMgmtMapper.insertBillItmInfo */
INSERT INTO MSP_BILL_ITM_INFO (
	BILL_ITEM_CD
	, ITEM_CD_NM
	, APPL_STRT_DT
	, APPL_END_DT
	, KT_INV_CD
	, KT_INV_RATE
	, ACNT_TP
	, STTL_ITM_CD
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	UPPER(#{billItemCd, jdbcType=VARCHAR})
	, UPPER(#{itemCdNm, jdbcType=VARCHAR})
	, #{applStrtDt, jdbcType=VARCHAR}
	, NVL(#{applEndDt, jdbcType=VARCHAR}, '99991231')
	, #{ktInvCd, jdbcType=VARCHAR}
	, #{ktInvRate, jdbcType=FLOAT}
	, #{acntTp, jdbcType=VARCHAR}
	, #{sttlItmCd, jdbcType=VARCHAR}
	, #{sessionUserId, jdbcType=VARCHAR}
	, SYSDATE
	, #{sessionUserId, jdbcType=VARCHAR}
	, SYSDATE
)

mapper.update:
/* statMgmtMapper.updateBillItemInfo */
UPDATE  MSP_BILL_ITM_INFO
SET     RVISN_ID = #{sessionUserId}
        , RVISN_DTTM = SYSDATE
        , ITEM_CD_NM = #{itemCdNm} 
        , ACNT_TP = #{acntTp} 
        , STTL_ITM_CD = #{sttlItmCd} 
        , APPL_END_DT = TO_CHAR(TO_DATE(#{applStrtDt}, 'YYYYMMDD') - 1, 'YYYYMMDD') 
WHERE   BILL_ITEM_CD = #{billItemCd}
AND     APPL_END_DT = #{applEndDt}

mapper.select:
/* statMgmtMapper.getBillItmChk */
SELECT  COUNT(1) CHK
FROM    MSP_BILL_ITM_INFO
WHERE   BILL_ITEM_CD = #{billItemCd}
AND     APPL_END_DT  <=  #{applEndDt}
AND     APPL_STRT_DT  >=  #{applStrtDt}

/* statMgmtMapper.getInvPymPrdCheck */
SELECT COUNT(1) CNT FROM DUAL
WHERE   TO_CHAR(ADD_MONTHS(TO_DATE(#{endYm}, 'YYYYMM'), -60), 'YYYYMM')  <  #{strtYm}

/* statMgmtMapper.getInvPymDataList */
SELECT B.CONTRACT_NUM , A.OPEN_DT , A.SUB_STATUS , FN_GET_CODENM('MSP0003', A.SUB_STATUS) AS SUB_STATUS_NM , FN_GET_CODENM('CMN0032', A.LST_PAY_CL_CD) AS PPPO , A.AGRM_MNTH_CNT AS ENGG_MNTH_CNT , A.LST_RATE_CD AS RATE_CD , ( SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.LST_RATE_CD AND ROWNUM = 1 ) AS RATE_NM , #{strtYm} || '~' || #{endYm} AS BILL_YM , B.INV_AMNT , B.PYM_AMNT , B.INV_AMNT - B.PYM_AMNT AS UNPD_AMNT , CASE WHEN B.INV_AMNT = 0 THEN 0 ELSE ROUND(( B.INV_AMNT - B.PYM_AMNT ) / B.INV_AMNT * 100, 1) END AS UNPD_RATIO , CASE WHEN B.INV_AMNT - B.PYM_AMNT > 0 THEN 'Y' ELSE 'N' END AS UNPD_YN FROM MSP_DAILY_CLOSE_STTC A , ( SELECT A.CRT_YM , A.CONTRACT_NUM , SUM(A.INV_AMNT) AS INV_AMNT , SUM(A.PYM_AMNT) AS PYM_AMNT FROM MSP_INV_PYM_ACNT_DATA A WHERE A.CRT_YM = #{trgtYm} AND A.BILL_YM BETWEEN #{strtYm} AND #{endYm} GROUP BY A.CRT_YM, A.CONTRACT_NUM ) B WHERE B.CONTRACT_NUM = A.CONTRACT_NUM(+)
AND B.CONTRACT_NUM = #{contractNum}
AND A.LST_PAY_CL_CD = #{pppo}
AND B.INV_AMNT - B.PYM_AMNT > 0

/* statMgmtMapper.getInvPymDataCheck */
SELECT  COUNT(1) AS CNT 
FROM    CLS_SCHD_LOG 
WHERE   SCHD_ID = 'INVPYMDATA' 
AND     PARAM = #{sessionUserId} || '-' || #{trgtYm} || '-' || #{strtYm} || '-' || #{endYm} 
AND     PROC_STAT_CD = 'P'

mapper.insert:
{ CALL P_ACNT_DATA_PROC(
				#{trgtYm, jdbcType=VARCHAR}
				, #{strtYm, jdbcType=VARCHAR}
				, #{endYm, jdbcType=VARCHAR}
				, #{sessionUserId, jdbcType=VARCHAR}
	) }

mapper.sql:
SELECT B.CONTRACT_NUM AS contractNum , B.SUB_LINK_NAME AS custNm , B.SUBSCRIBER_NO AS subscriberNo , B.SUB_STATUS AS subStatus , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS subStatusNm , B.LST_COM_ACTV_DATE AS openDt , DECODE(B.SUB_STATUS, 'C', SUBSTR(B.SUB_STATUS_DATE, 1, 8), '') AS tmntDt , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm , A.VC_USG_AMNT + A.SC_USG_AMNT AS callUsgAmnt , A.VC_FREE_AMNT + A.SC_FREE_AMNT AS callFreeAmnt , A.VC_OVER_AMNT + A.SC_OVER_AMNT AS callOverAmnt , A.SMS_USG_CNT + A.MMS_USG_CNT + A.LMS_USG_CNT AS charUsgCnt , A.SMS_FREE_CNT + A.MMS_FREE_CNT + A.LMS_FREE_CNT AS charFreeCnt , A.SMS_OVER_CNT + A.MMS_OVER_CNT + A.LMS_OVER_CNT AS charOverCnt , ROUND(A.DATA_USG_AMNT * 512 / 1024 / 1024, 2) AS dataUsgAmnt , ROUND(A.DATA_FREE_AMNT * 512 / 1024 / 1024, 2) AS dataFreeAmnt , ROUND(A.DATA_OVER_AMNT * 512 / 1024 / 1024, 2) AS dataOverAmnt , A.ROAM_USG_AMNT AS roamUsgAmnt , A.ROAM_FREE_AMNT AS roamFreeAmnt , A.ROAM_OVER_AMNT AS roamOverAmnt FROM MSP_USG_AMNT_STTC A , MSP_JUO_SUB_INFO B WHERE A.USG_YM = #{usgYm} AND SUBSTR(B.LST_COM_ACTV_DATE,1,6) = #{openYm} AND A.CONTRACT_NUM = B.CONTRACT_NUM AND B.PPPO = 'PO'
AND (A.CONTRACT_NUM = #{searchVal} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
AND B.SUB_LINK_NAME LIKE '%' || #{searchVal} || '%'
AND B.SUBSCRIBER_NO = #{searchVal}
AND B.OPEN_AGNT_CD = #{orgnId}

mapper.select:
/* statMgmtMapper.getDaily3gSubList */
SELECT CONTRACT_NUM , DECODE(REQ_BUY_TYPE,'UU','유심구매','MM','단말구매','') AS REQ_BUY_TYPE , LST_COM_ACTV_DATE , BIRTH_DT , GENDER , FN_GET_CODENM('RCP0037', SUB_STATUS) AS SUB_STATUS , OPEN_AGNT_CD , OPEN_AGNT_NM , LST_RATE_CD , LST_RATE_NM , FN_GET_CODENM('CMN0266', LST_RATE_TP) AS LST_RATE_TP , LST_MODEL_ID , LST_MODEL_NM , FN_GET_CODENM('CMN0266', LST_MODEL_TP) AS LST_MODEL_TP , MODEL_VOLTE_YN , MODEL_NFC_YN , LST_USIM_ID , LST_USIM_NM , FN_GET_CODENM('CMN0266', LST_USIM_TP) AS LST_USIM_TP , USIM_VOLTE_YN , USIM_NFC_YN , FN_GET_CODENM('CMN0058', BL_DC_TYPE) AS BL_DC_TYPE , ARGM_STRT_DT , ARGM_END_DT , STOP_DT , FN_GET_CODENM('MSP0004', STOP_RSN_CD) AS STOP_RSN_NM , FN_GET_CODENM('RCP0036', BILL_SEND_CD) AS BILL_SEND_NM FROM MSP_DAILY_3G_SUB WHERE STDR_DT = #{stdrDt}
AND SUB_STATUS = #{subStatus}
AND CONTRACT_NUM = #{searchVal}
AND LST_MODEL_ID IS NULL
AND LST_MODEL_TP = #{lstModelTp}
AND LST_RATE_TP = #{lstRateTp}
AND LST_USIM_TP = #{lstUsimTp}
AND MODEL_VOLTE_YN = #{volteYn}
ORDER BY LST_COM_ACTV_DATE DESC
